import React, { useEffect, useState } from 'react';
import '../style/Card.css';
import { useOrderContext } from '../contextAPI/OrderCartContext';

const CartItemCard = ({ name, description, price, image }) => {
  const context = useOrderContext();
  const [updateTrigger, setUpdateTrigger] = useState(context.order[name]?.quantity);  // Force update state
  const quantity = context.order[name]?.quantity || 0;

  useEffect(() => {
    setUpdateTrigger(prev => !prev);  // Toggle update state to force re-render
  }, [context.order]);

  const handleIncrement = () => {
    context.addToOrder(name, 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) {
      context.addToOrder(name, -1);
    } else if (quantity === 1) {
      context.removeFromOrder(name);
    }
  };

  const handleRemove = () => {
    context.removeFromOrder(name);
  };

  const totalAmount = price * quantity;

  return (
    <div className="cart-item-card">
      <button onClick={handleRemove} className="remove-button">✕</button>
      {image && <img src={image} alt={name} className="cart-item-image" />}
      <div className="cart-item-details">
        <h3>{name}</h3>
        <p>{description}</p>
        <div className="quantity-controls">
          <button onClick={handleDecrement} className="quantity-btn" disabled={quantity === 0}>-</button>
          <span className="quantity-display">{updateTrigger}</span>
          <button onClick={handleIncrement} className="quantity-btn">+</button>
        </div>
        <p>Price: ${price.toFixed(2)}</p>
        <p>Total: ${totalAmount.toFixed(2)}</p>
      </div>
    </div>
  );
};

export default CartItemCard;
